using UnityEngine;
using UnityEngine.Purchasing;
using System;

public class PlayerStats : MonoBehaviour
{
    [Header("Core Stats (Public)")]
    public int level = 1;
    public int maxHealth = 100;
    public int currentHealth = 100;

    [Header("Combat (Public)")]
    public int baseDamage = 10;
    public float damageMultiplier = 1f;
    public float critChance = 0.1f;
    public float critMultiplier = 2f;

    [Header("Economy (Public)")]
    public int softCurrency = 0;
    public int premiumCurrency = 0;

    [Header("Progression (Public)")]
    public int damageUpgradeLevel = 0;
    public int healthUpgradeLevel = 0;
    public int shopDiscountLevel = 0;

    [Header("Tuning (Public)")]
    public int damageUpgradeBasePrice = 50;
    public float damageUpgradePriceGrowth = 1.25f;
    public int healthUpgradeBasePrice = 40;
    public float healthUpgradePriceGrowth = 1.22f;
    public int discountUpgradeBasePrice = 200;
    public float discountUpgradePriceGrowth = 1.35f;

    [Range(0f, 0.75f)]
    public float maxDiscountPercent = 0.35f;
    public float discountPerLevel = 0.02f;

    public event Action<int, int> OnHealthChanged;
    public event Action<int, int> OnCurrencyChanged;

    void Awake()
    {
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
        NotifyHealth();
        NotifyCurrency();
    }

    public void Heal(int amount)
    {
        if (amount <= 0) return;
        currentHealth = Mathf.Clamp(currentHealth + amount, 0, maxHealth);
        NotifyHealth();
    }

    public void TakeDamage(int incomingDamage)
    {
        if (incomingDamage <= 0) return;
        currentHealth = Mathf.Clamp(currentHealth - incomingDamage, 0, maxHealth);
        NotifyHealth();
    }

    public int CalculateOutgoingDamage(System.Random rng = null)
    {
        float dmg = baseDamage;
        dmg *= (1f + damageUpgradeLevel * 0.08f);
        dmg *= Mathf.Max(0.01f, damageMultiplier);

        bool crit = false;
        float roll = 0f;

        if (rng != null)
        {
            roll = (float)rng.NextDouble();
            crit = roll < Mathf.Clamp01(critChance);
        }
        else
        {
            roll = UnityEngine.Random.value;
            crit = roll < Mathf.Clamp01(critChance);
        }

        if (crit)
            dmg *= Mathf.Max(1f, critMultiplier);

        return Mathf.Max(1, Mathf.RoundToInt(dmg));
    }

    public int CalculateIncomingDamage(int rawDamage, float armorPercentReduction)
    {
        armorPercentReduction = Mathf.Clamp01(armorPercentReduction);
        float reduced = rawDamage * (1f - armorPercentReduction);
        return Mathf.Max(0, Mathf.RoundToInt(reduced));
    }

    public void AddSoftCurrency(int amount)
    {
        if (amount == 0) return;
        softCurrency = Mathf.Max(0, softCurrency + amount);
        NotifyCurrency();
    }

    public void AddPremiumCurrency(int amount)
    {
        if (amount == 0) return;
        premiumCurrency = Mathf.Max(0, premiumCurrency + amount);
        NotifyCurrency();
    }

    public bool SpendSoftCurrency(int amount)
    {
        if (amount <= 0) return true;
        if (softCurrency < amount) return false;
        softCurrency -= amount;
        NotifyCurrency();
        return true;
    }

    public bool SpendPremiumCurrency(int amount)
    {
        if (amount <= 0) return true;
        if (premiumCurrency < amount) return false;
        premiumCurrency -= amount;
        NotifyCurrency();
        return true;
    }

    public void IncreaseMaxHealth(int amount)
    {
        if (amount <= 0) return;
        maxHealth = Mathf.Max(1, maxHealth + amount);
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);
        NotifyHealth();
    }

    public void FullHeal()
    {
        currentHealth = maxHealth;
        NotifyHealth();
    }

    public float GetDiscountPercent()
    {
        float d = shopDiscountLevel * discountPerLevel;
        return Mathf.Clamp(d, 0f, maxDiscountPercent);
    }

    public int ApplyDiscount(int price)
    {
        float discount = GetDiscountPercent();
        float discounted = price * (1f - discount);
        return Mathf.Max(0, Mathf.RoundToInt(discounted));
    }

    public int GetDamageUpgradePrice()
    {
        float p = damageUpgradeBasePrice * Mathf.Pow(damageUpgradePriceGrowth, damageUpgradeLevel);
        return ApplyDiscount(Mathf.Max(1, Mathf.RoundToInt(p)));
    }

    public int GetHealthUpgradePrice()
    {
        float p = healthUpgradeBasePrice * Mathf.Pow(healthUpgradePriceGrowth, healthUpgradeLevel);
        return ApplyDiscount(Mathf.Max(1, Mathf.RoundToInt(p)));
    }

    public int GetDiscountUpgradePrice()
    {
        float p = discountUpgradeBasePrice * Mathf.Pow(discountUpgradePriceGrowth, shopDiscountLevel);
        return Mathf.Max(1, Mathf.RoundToInt(p));
    }

    public bool TryBuyDamageUpgrade()
    {
        int price = GetDamageUpgradePrice();
        if (!SpendSoftCurrency(price)) return false;
        damageUpgradeLevel++;
        return true;
    }

    public bool TryBuyHealthUpgrade()
    {
        int price = GetHealthUpgradePrice();
        if (!SpendSoftCurrency(price)) return false;
        healthUpgradeLevel++;
        IncreaseMaxHealth(10);
        Heal(10);
        return true;
    }

    public bool TryBuyDiscountUpgrade()
    {
        int price = GetDiscountUpgradePrice();
        if (!SpendSoftCurrency(price)) return false;
        shopDiscountLevel++;
        return true;
    }

    void NotifyHealth()
    {
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
    }

    void NotifyCurrency()
    {
        OnCurrencyChanged?.Invoke(softCurrency, premiumCurrency);
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats player;

    [Header("Consumables (Soft Currency)")]
    public int smallHealAmount = 25;
    public int smallHealBasePrice = 30;
    public float smallHealPriceGrowth = 1.10f;
    public int smallHealPurchasedCount = 0;

    [Header("Consumables (Premium Currency)")]
    public int revivePremiumPrice = 5;

    public int GetSmallHealPrice()
    {
        if (player == null) return 0;
        float p = smallHealBasePrice * Mathf.Pow(smallHealPriceGrowth, smallHealPurchasedCount);
        int price = Mathf.Max(1, Mathf.RoundToInt(p));
        return player.ApplyDiscount(price);
    }

    public bool TryBuySmallHeal()
    {
        if (player == null) return false;
        int price = GetSmallHealPrice();
        if (!player.SpendSoftCurrency(price)) return false;
        smallHealPurchasedCount++;
        player.Heal(smallHealAmount);
        return true;
    }

    public bool TryBuyRevive()
    {
        if (player == null) return false;
        if (player.currentHealth > 0) return false;
        if (!player.SpendPremiumCurrency(revivePremiumPrice)) return false;
        player.currentHealth = Mathf.Max(1, Mathf.RoundToInt(player.maxHealth * 0.35f));
        return true;
    }
}

