public class SimpleSaveLoad : MonoBehaviour
{
    public PlayerStats player;
    public ShopManager shop;

    const string Key = "PLAYER_SAVE_V1";

    [Serializable]
    class SaveData
    {
        public int level;
        public int maxHealth;
        public int currentHealth;

        public int baseDamage;
        public float damageMultiplier;
        public float critChance;
        public float critMultiplier;

        public int softCurrency;
        public int premiumCurrency;

        public int damageUpgradeLevel;
        public int healthUpgradeLevel;
        public int shopDiscountLevel;

        public int smallHealPurchasedCount;
    }

    public void Save()
    {
        if (player == null) return;

        var d = new SaveData
        {
            level = player.level,
            maxHealth = player.maxHealth,
            currentHealth = player.currentHealth,

            baseDamage = player.baseDamage,
            damageMultiplier = player.damageMultiplier,
            critChance = player.critChance,
            critMultiplier = player.critMultiplier,

            softCurrency = player.softCurrency,
            premiumCurrency = player.premiumCurrency,

            damageUpgradeLevel = player.damageUpgradeLevel,
            healthUpgradeLevel = player.healthUpgradeLevel,
            shopDiscountLevel = player.shopDiscountLevel,

            smallHealPurchasedCount = shop != null ? shop.smallHealPurchasedCount : 0
        };

        string json = JsonUtility.ToJson(d);
        PlayerPrefs.SetString(Key, json);
        PlayerPrefs.Save();
    }

    public void Load()
    {
        if (player == null) return;
        if (!PlayerPrefs.HasKey(Key)) return;

        string json = PlayerPrefs.GetString(Key);
        var d = JsonUtility.FromJson<SaveData>(json);
        if (d == null) return;

        player.level = d.level;
        player.maxHealth = Mathf.Max(1, d.maxHealth);
        player.currentHealth = Mathf.Clamp(d.currentHealth, 0, player.maxHealth);

        player.baseDamage = Mathf.Max(1, d.baseDamage);
        player.damageMultiplier = d.damageMultiplier;
        player.critChance = d.critChance;
        player.critMultiplier = d.critMultiplier;

        player.softCurrency = Mathf.Max(0, d.softCurrency);
        player.premiumCurrency = Mathf.Max(0, d.premiumCurrency);

        player.damageUpgradeLevel = Mathf.Max(0, d.damageUpgradeLevel);
        player.healthUpgradeLevel = Mathf.Max(0, d.healthUpgradeLevel);
        player.shopDiscountLevel = Mathf.Max(0, d.shopDiscountLevel);

        if (shop != null)
            shop.smallHealPurchasedCount = Mathf.Max(0, d.smallHealPurchasedCount);

        player.FullHeal();
        player.AddSoftCurrency(0);
        player.AddPremiumCurrency(0);
    }

    public void Wipe()
    {
        PlayerPrefs.DeleteKey(Key);
        PlayerPrefs.Save();
    }
}

public class IAPManager : MonoBehaviour, IStoreListener
{
    public PlayerStats player;

    [Header("Product IDs")]
    public string premiumSmallPackId = "premium_small_pack";
    public string premiumMediumPackId = "premium_medium_pack";
    public string premiumLargePackId = "premium_large_pack";

    [Header("Rewards")]
    public int premiumSmallPackAmount = 20;
    public int premiumMediumPackAmount = 60;
    public int premiumLargePackAmount = 150;

    IStoreController controller;
    IExtensionProvider extensions;

    void Start()
    {
        InitializePurchasing();
    }

    public void InitializePurchasing()
    {
        if (controller != null) return;

        var builder = ConfigurationBuilder.Instance(StandardPurchasingModule.Instance());

        builder.AddProduct(premiumSmallPackId, ProductType.Consumable);
        builder.AddProduct(premiumMediumPackId, ProductType.Consumable);
        builder.AddProduct(premiumLargePackId, ProductType.Consumable);

        UnityPurchasing.Initialize(this, builder);
    }

    public void BuySmallPack() => BuyProduct(premiumSmallPackId);
    public void BuyMediumPack() => BuyProduct(premiumMediumPackId);
    public void BuyLargePack() => BuyProduct(premiumLargePackId);

    void BuyProduct(string productId)
    {
        if (controller == null) return;
        Product p = controller.products.WithID(productId);
        if (p == null || !p.availableToPurchase) return;
        controller.InitiatePurchase(p);
    }

    public void OnInitialized(IStoreController controller, IExtensionProvider extensions)
    {
        this.controller = controller;
        this.extensions = extensions;
    }

    public void OnInitializeFailed(InitializationFailureReason error) { }
    public void OnInitializeFailed(InitializationFailureReason error, string message) { }

    public PurchaseProcessingResult ProcessPurchase(PurchaseEventArgs e)
    {
        if (player == null) return PurchaseProcessingResult.Complete;

        string id = e.purchasedProduct.definition.id;

        if (string.Equals(id, premiumSmallPackId, StringComparison.Ordinal))
            player.AddPremiumCurrency(premiumSmallPackAmount);
        else if (string.Equals(id, premiumMediumPackId, StringComparison.Ordinal))
            player.AddPremiumCurrency(premiumMediumPackAmount);
        else if (string.Equals(id, premiumLargePackId, StringComparison.Ordinal))
            player.AddPremiumCurrency(premiumLargePackAmount);

        return PurchaseProcessingResult.Complete;
    }

    public void OnPurchaseFailed(Product product, PurchaseFailureReason failureReason) { }
}